import tensorflow as tfimport matplotlib.pyplot as pltmnist = tf.keras.datasets.mnist(train_x, train_y), (test_x, test_y) = mnist.load_data()x_train = train_x.reshape(60000, 784).astype('float32') / 255x_test = test_x.reshape(10000, 784).astype('float32') / 255print(x_train.shape)model = tf.keras.models.Sequential([    tf.keras.layers.Dense(128, activation='relu'),    tf.keras.layers.Dense(64, activation='relu'),    tf.keras.layers.Dense(32, activation='relu'),    tf.keras.layers.Dense(10, activation='softmax')])model.compile(optimizer='sgd',              loss='sparse_categorical_crossentropy',              metrics=['accuracy'])model.fit(x_train, train_y, batch_size=64, epochs=1, validation_data=(x_test, test_y), validation_freq=1)model.summary()# 通过model的get_config方法获取模型结构config = model.get_config()# 通过model的to_json方法获取json格式模型结构json_config = model.to_json()with open('./model/model_config.json', 'w') as json_file:    json_file.write(json_config)# # 获取权重# weights = model.get_weights()## # 给模型设置权重# model.set_weights(weights)# 保存权重到磁盘model.save_weights('./model/weights.h5')del model        # 删除原有网络结构'''加载模型结构和参数，识别测试集中的手写数字'''plt.imshow(test_x[1], cmap='gray')plt.show()with open('./model/model_config.json') as json_file:    json_config = json_file.read()# json_config对象加载模型结构new_model = tf.keras.models.model_from_json(json_config)# 加载模型参数new_model.load_weights('./model/weights.h5')predict = new_model(x_test)[1]print(tf.argmax(predict))